    public Dictionary<string, string> ParseConfigurationXml(string xmlFilePath)
    {
        var settings = new Dictionary<string, string>();
        
        XmlReaderSettings readerSettings = new XmlReaderSettings
        {
            DtdProcessing = DtdProcessing.Parse,
            ValidationType = ValidationType.DTD,
            XmlResolver = new XmlUrlResolver(),
            IgnoreWhitespace = true,
            IgnoreComments = true
        };

        using (XmlReader reader = XmlReader.Create(xmlFilePath, readerSettings))
        {
            while (reader.Read())
            {
                if (reader.NodeType == XmlNodeType.Element && reader.Name == "setting")
                {
                    string key = reader.GetAttribute("key");
                    string value = reader.GetAttribute("value");
                    
                    if (!string.IsNullOrEmpty(key))
                    {
                        settings[key] = value ?? string.Empty;
                    }
                }
                else if (reader.NodeType == XmlNodeType.Element && reader.Depth > 0)
                {
                    string elementName = reader.Name;
                    
                    if (reader.HasAttributes)
                    {
                        while (reader.MoveToNextAttribute())
                        {
                            string key = $"{elementName}.{reader.Name}";
                            settings[key] = reader.Value;
                        }
                        reader.MoveToElement();
                    }
                    
                    if (!reader.IsEmptyElement)
                    {
                        string content = reader.ReadElementContentAsString();
                        if (!string.IsNullOrWhiteSpace(content))
                        {
                            settings[elementName] = content.Trim();
                        }
                    }
                }
            }
        }

        return settings;
    }

    public Dictionary<string, string> ParseConfigurationXmlWithXmlDocument(string xmlFilePath)
    {
        var settings = new Dictionary<string, string>();
        
