                    string key = node.Attributes["key"].Value;
                    string value = node.Attributes["value"]?.Value ?? string.Empty;
                    settings[key] = value;
                }
            }
        }

        ParseElementsRecursively(doc.DocumentElement, settings, "");

        return settings;
    }

    private void ParseElementsRecursively(XmlNode node, Dictionary<string, string> settings, string parentPath)
    {
        if (node == null) return;

        string currentPath = string.IsNullOrEmpty(parentPath) 
            ? node.Name 
            : $"{parentPath}.{node.Name}";

        if (node.Name == "setting") return;

        if (node.Attributes != null && node.Attributes.Count > 0)
        {
            foreach (XmlAttribute attr in node.Attributes)
            {
                string key = $"{currentPath}.{attr.Name}";
                settings[key] = attr.Value;
            }
        }

        if (node.ChildNodes.Count == 1 && node.FirstChild.NodeType == XmlNodeType.Text)
        {
            string textValue = node.InnerText.Trim();
            if (!string.IsNullOrWhiteSpace(textValue))
            {
                settings[currentPath] = textValue;
            }
        }
        else
        {
            foreach (XmlNode childNode in node.ChildNodes)
            {
                if (childNode.NodeType == XmlNodeType.Element)
                {
                    ParseElementsRecursively(childNode, settings, currentPath);
                }
            }
        }
    }

